// Gmail-specific patterns — merchant receipts, Play Store, Steam, etc.
// Same pattern-loading mechanism as Outlook workflow.
// Gmail emails are used for cross-verification and merchant enrichment,
// not as the primary transaction source.

const body = $('Insert raw event').item.json.snippet || '';
const subject = $('Insert raw event').item.json.subject || '';
const sender = $('Insert raw event').item.json.sender || '';
const rawEventId = $('Insert raw event').item.json.id;

const patterns = $input.first().json.patterns || [];

for (const p of patterns) {
  if (p.source !== 'gmail' && p.source !== 'any') continue;
  if (p.sender && !sender.includes(p.sender)) continue;

  const re = new RegExp(p.pattern, 'i');
  const match = body.match(re) || subject.match(re);
  if (!match || !match.groups) continue;

  const g = match.groups;
  const amount = parseFloat((g.amount || '').replace(/,/g, ''));
  if (isNaN(amount)) continue;

  return [{
    json: {
      raw_event_id: rawEventId,
      parse_method: 'regex',
      pattern_name: p.name,
      utr: g.utr || g.order_id || null,
      amount,
      currency: g.currency || 'INR',
      direction: g.direction || 'debit',
      merchant: (g.merchant || '').trim() || null,
      account: 'gpay',
      category_hint: (g.merchant || '').trim().toLowerCase() || null,
      transaction_time: g.date || new Date($('Fetch Gmail emails').item.json.internalDate * 1).toISOString(),
      parse_success: true,
      source: 'gmail'
    }
  }];
}

return [{ json: { raw_event_id: rawEventId, parse_success: false, source: 'gmail' } }];
